const q = $json.query || {};
return [{
  json: {
    type: String(q.type || '').trim(),
    id: String(q.id || '').trim(),
    tenant_id: String(q.tenant_id || '').trim(),
  },
}];

const query = $('Parse Query').item.json;
const tenant = $('Get Tenant Row').item.json || {};
const type = query.type;

const row = type === 'appointment'
  ? ($('Get Appointment Row').item.json || {})
  : ($('Get Restaurant Row').item.json || {});

const activity = tenant.nome_attivita || query.tenant_id || 'Zirèl';

const pad = (v) => String(v).padStart(2, '0');

const parseDateTimeParts = (dateValue, timeValue) => {
  const dateRaw = String(dateValue || '').trim();
  const timeRaw = String(timeValue || '').trim();
  if (!dateRaw || !timeRaw) return null;

  const [year, month, day] = dateRaw.split('-').map(Number);
  const [hour, minute] = timeRaw.split(':').map(Number);

  if (!year || !month || !day || Number.isNaN(hour) || Number.isNaN(minute)) return null;

  return { year, month, day, hour, minute };
};

const toLocalStamp = (parts) => {
  if (!parts) return '';
  return `${parts.year}${pad(parts.month)}${pad(parts.day)}T${pad(parts.hour)}${pad(parts.minute)}00`;
};

const toUtcStamp = (dateObj) => {
  if (!dateObj) return '';
  return `${dateObj.getUTCFullYear()}${pad(dateObj.getUTCMonth() + 1)}${pad(dateObj.getUTCDate())}T${pad(dateObj.getUTCHours())}${pad(dateObj.getUTCMinutes())}${pad(dateObj.getUTCSeconds())}Z`;
};

const addMinutes = (parts, minutesToAdd) => {
  if (!parts) return null;
  const d = new Date(Date.UTC(parts.year, parts.month - 1, parts.day, parts.hour, parts.minute + minutesToAdd, 0));
  return {
    year: d.getUTCFullYear(),
    month: d.getUTCMonth() + 1,
    day: d.getUTCDate(),
    hour: d.getUTCHours(),
    minute: d.getUTCMinutes(),
  };
};

const escapeIcs = (value) =>
  String(value || '')
    .replace(/\\/g, '\\\\')
    .replace(/\n/g, '\\n')
    .replace(/,/g, '\\,')
    .replace(/;/g, '\\;');

let title = '';
let description = '';
let startParts = null;
let endParts = null;

const uid = `${query.type}-${query.id}@zirel.org`;

if (type === 'appointment') {
  title = `Appuntamento - ${row.nome || 'Cliente'}`;
  description = [
    `Attività: ${activity}`,
    `Cliente: ${row.nome || 'N/D'}`,
    `Telefono: ${row.telefono || 'N/D'}`,
    `Email: ${row.email || 'N/D'}`,
    `Motivo: ${row.motivo || row.note || 'N/D'}`
  ].join('\n');

  startParts = parseDateTimeParts(row.data_appuntamento, row.orario || '10:00');
  endParts = addMinutes(startParts, 30);
} else {
  title = `Prenotazione tavolo - ${row.nome_cliente || 'Cliente'}`;
  description = [
    `Attività: ${activity}`,
    `Cliente: ${row.nome_cliente || 'N/D'}`,
    `Telefono: ${row.telefono || 'N/D'}`,
    `Persone: ${row.persone || 'N/D'}`,
    `Note: ${row.note_prenotazione || 'Nessuna'}`
  ].join('\n');

  startParts = parseDateTimeParts(row.data_prenotazione, row.ora || '20:00');
  endParts = addMinutes(startParts, 120);
}

if (!startParts || !endParts) {
  throw new Error(`Impossibile generare ICS: data/ora mancanti o non valide per type=${type}, id=${query.id}`);
}

const nowUtc = new Date();

const ics = [
  'BEGIN:VCALENDAR',
  'VERSION:2.0',
  'PRODID:-//Zirel//Calendar Export//IT',
  'CALSCALE:GREGORIAN',
  'METHOD:PUBLISH',
  'X-WR-TIMEZONE:Europe/Rome',
  'BEGIN:VEVENT',
  `UID:${uid}`,
  `DTSTAMP:${toUtcStamp(nowUtc)}`,
  `DTSTART;TZID=Europe/Rome:${toLocalStamp(startParts)}`,
  `DTEND;TZID=Europe/Rome:${toLocalStamp(endParts)}`,
  `SUMMARY:${escapeIcs(title)}`,
  `DESCRIPTION:${escapeIcs(description)}`,
  `LOCATION:${escapeIcs(activity)}`,
  'STATUS:CONFIRMED',
  'END:VEVENT',
  'END:VCALENDAR'
].join('\r\n');

return [{
  json: {
    ics,
    filename: `${type}-${query.id}.ics`
  }
}];

